// Code pour nœud Code n8n - Classement Instagram avec output simplifié
// Récupérer les données d'entrée
const items = $input.all();

// Filtrer uniquement les posts principaux (exclure les carousel_item)
const posts = items.filter(item => {
  const post = item.json;
  return post.productType !== 'carousel_item' && post.url && post.url.includes('/p/');
});

// Calculer le score pour chaque post
const postsWithScore = posts.map(item => {
  const post = item.json;

  // likesCount peut être -1 si masqué par Instagram → on traite comme 0
  const likes = (post.likesCount && post.likesCount > 0) ? post.likesCount : 0;
  const comments = post.commentsCount || 0;

  // Calcul du score : (likes × 1) + (comments × 2)
  const totalScore = (likes * 1) + (comments * 2);

  return {
    json: {
      url: post.url,
      caption: post.caption || "Pas de caption",
      score: totalScore,
      details: {
        likes: likes,
        comments: comments,
        type: post.type,
        author: post.ownerUsername || 'inconnu',
        timestamp: post.timestamp
      }
    }
  };
});

// Trier par score décroissant
const sortedPosts = postsWithScore.sort((a, b) => b.json.score - a.json.score);

// Prendre les 10 meilleurs
const top10Posts = sortedPosts.slice(0, 10);

// Ajouter un rang à chaque post
const rankedPosts = top10Posts.map((post, index) => ({
  json: {
    rank: index + 1,
    url: post.json.url,
    caption: post.json.caption,
    score: post.json.score
  }
}));

// Log pour debug
console.log(`🏆 TOP 10 POSTS INSTAGRAM - Score = (likes×1) + (comments×2)`);
console.log(`────────────────────────────────────────────────────────────`);
rankedPosts.forEach((post) => {
  const p = post.json;
  const shortCaption = p.caption.length > 60 ? p.caption.substring(0, 60) + '...' : p.caption;
  console.log(`${p.rank}. Score: ${p.score}`);
  console.log(`   URL: ${p.url}`);
  console.log(`   Caption: "${shortCaption}"`);
  console.log(`   ────────────────────────────────────────────────────────`);
});
console.log(`\n📊 Analysé ${posts.length} posts au total`);

return rankedPosts;

