// Code pour nœud Code n8n - Classement Instagram
// Récupérer le keyword dynamiquement
const keyword = $('Loop Over Query').first().json.Query;

// Récupérer les données du nœud précédent
const instagramData = $('Sort Instagram').all();

console.log(`📥 Récupération des données:`);
console.log(`- Instagram: ${instagramData.length} posts`);

// Fonction pour déterminer le level basé sur le score
function getLevel(score) {
  if (score >= 10000) return 'High';
  if (score >= 1000) return 'Medium';
  return 'Low';
}

// Fonction pour extraire l'auteur Instagram
function getAuthor(item) {
  const instaMatch = item.url.match(/instagram\.com\/([^\/]+)/);
  return instaMatch ? `@${instaMatch[1]}` : '@inconnu';
}

// Transformer les données Instagram
const instagramPosts = instagramData.map(item => ({
  json: {
    source: 'Instagram',
    keyword: keyword,
    author: getAuthor(item.json),
    content: (item.json.caption || 'Pas de caption').substring(0, 50) + '...',
    score: item.json.score,
    level: getLevel(item.json.score),
    url: item.json.url,
    originalRank: item.json.rank
  }
}));

// Trier par score décroissant
const sortedPosts = instagramPosts.sort((a, b) => b.json.score - a.json.score);

// Ajouter le rang
const rankedPosts = sortedPosts.map((post, index) => ({
  json: {
    ...post.json,
    rank: index + 1,
    date: new Date().toISOString().split('T')[0]
  }
}));

// Prendre le top 15
const topPosts = rankedPosts.slice(0, 15);

// Statistiques par niveau
const stats = {
  total: topPosts.length,
  byLevel: {
    High: topPosts.filter(p => p.json.level === 'High').length,
    Medium: topPosts.filter(p => p.json.level === 'Medium').length,
    Low: topPosts.filter(p => p.json.level === 'Low').length
  }
};

// Log pour debug
console.log(`🏆 TOP ${topPosts.length} POSTS INSTAGRAM - Mot-clé: "${keyword}"`);
console.log(`────────────────────────────────────────────────────────────────────────────────`);

topPosts.forEach((post) => {
  const p = post.json;
  console.log(`${p.rank}. ${p.author} - Score: ${p.score.toLocaleString()} (${p.level})`);
  console.log(`   Contenu: "${p.content}"`);
  console.log(`   URL: ${p.url}`);
  console.log(`   ────────────────────────────────────────────────────────────────────────────`);
});

console.log(`\n📊 STATISTIQUES:`);
console.log(`Total: ${stats.total} posts`);
console.log(`Par niveau: High(${stats.byLevel.High}) | Medium(${stats.byLevel.Medium}) | Low(${stats.byLevel.Low})`);

// Retourner le classement
return topPosts;
